export const code = async (inputs) => {
  const BACKEND = 'http://backend:8000';
  const MIN_COVERAGE = 1.0;

  const grades = Array.isArray(inputs.grades) ? inputs.grades : [];
  const distinct = [...new Set(grades.map((g) => g.origin_grade).filter((v) => v != null))];

  // Base filename (without extension) used to name the output file.
  const rawName = inputs.file_name || 'transcript';
  const base = rawName.replace(/\.[^/.]+$/, '') || 'transcript';

  const toBase64 = (str) => Buffer.from(str).toString('base64');

  // 1. Resolve the scale from country + observed grades (unauthenticated endpoint).
  const matchRes = await fetch(`${BACKEND}/scales/match`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ country: inputs.country || '', grades: distinct }),
  });
  const candidates = matchRes.ok ? await matchRes.json() : [];

  // 2. Decide confidence: best scale must fully cover the grades and not tie another.
  const top = candidates[0];
  const second = candidates[1];
  let reason = null;
  if (!top || top.coverage < MIN_COVERAGE) {
    reason = top ? 'low_coverage' : 'no_candidates';
  } else if (
    second &&
    second.coverage === top.coverage &&
    second.scale_total_grades === top.scale_total_grades
  ) {
    reason = 'ambiguous';
  }

  // 3a. Unresolved/ambiguous -> upload a needs-review artifact instead of guessing.
  if (reason) {
    const review = {
      status: 'NEEDS_REVIEW',
      reason,
      extracted: {
        country: inputs.country || null,
        grading_system: inputs.grading_system || null,
        grade_type: inputs.grade_type || null,
        grades,
      },
      candidates: candidates.slice(0, 5),
      instructions:
        'Pick the correct scale_id and re-run the transfer manually, or fix the country in the document and re-upload.',
    };
    return {
      needsReview: true,
      reason,
      file: toBase64(JSON.stringify(review, null, 2)),
      fileName: `${base}-NEEDS-REVIEW.json`,
      contentType: 'application/json',
    };
  }

  // 3b. Confident -> transfer only the grades the matched scale actually covers.
  const unmatched = new Set(top.unmatched_grades || []);
  const coveredGrades = grades.filter((g) => !unmatched.has(g.origin_grade));

  const response = await fetch(`${BACKEND}/transfer/?format=xlsx`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': process.env.FASTAPI_ACTIVEPIECES_API_KEY || '',
    },
    body: JSON.stringify({ scale_id: top.scale_id, grades: coveredGrades }),
  });

  const arrayBuffer = await response.arrayBuffer();
  const base64 = Buffer.from(arrayBuffer).toString('base64');

  return {
    needsReview: false,
    scale_id: top.scale_id,
    scale_description: top.scale_description,
    unmatched_grades: top.unmatched_grades || [],
    status: response.status,
    file: base64,
    fileName: `${base}-transfer.xlsx`,
    contentType: response.headers.get('content-type'),
  };
};
